import { ethers } from 'ethers';

async function connectWallet() {
  if (window.ethereum) {
    try {
      await window.ethereum.request({ method: 'eth_requestAccounts' });
      const provider = new ethers.providers.Web3Provider(window.ethereum);
      return provider.getSigner();
    } catch (error) {
      console.error('User rejected the request.');
    }
  } else {
    console.log('Please install MetaMask!');
  }
}

async function interactWithContract() {
  const signer = await connectWallet();
  if (!signer) return;

  const contractAddress = 'YOUR_CONTRACT_ADDRESS'; // Replace with your contract address
  const abi = [ // Replace with your contract's ABI
    "function yourFunctionName(paramType1, paramType2) external returns (returnType)"
  ];

  const contract = new ethers.Contract(contractAddress, abi, signer);

  const param1 = document.getElementById('param1').value; // Replace with your input IDs
  const param2 = document.getElementById('param2').value;

  try {
    const tx = await contract.yourFunctionName(param1, param2);
    console.log('Transaction sent:', tx.hash);
    // Wait for transaction to be mined
    const receipt = await tx.wait();
    console.log('Transaction mined:', receipt);
  } catch (error) {
    console.error('Error sending transaction:', error);
  }
}

// HTML elements for input and button, assumes you have inputs with IDs 'param1' and 'param2'
// and a button with ID 'interactButton' in your frontend
document.getElementById('interactButton').addEventListener('click', interactWithContract);